export const api = {
  signup: (payload) => request("/auth/signup", { method: "POST", body: payload }),
  login: (payload) => request("/auth/login", { method: "POST", body: payload }),
  me: () => request("/me"),
  updateMe: (payload) => request("/me", { method: "PUT", body: payload }),

  listInventory: () => request("/inventory"),
  addItem: (payload) => request("/inventory", { method: "POST", body: payload }),
  updateItem: (id, payload) => request(`/inventory/${id}`, { method: "PUT", body: payload }),
  deleteItem: (id) => request(`/inventory/${id}`, { method: "DELETE" }),

  quickAdd: (payload) => request("/ai/quick-add", { method: "POST", body: payload }),
  barcodeLookup: (payload) => request("/ai/barcode-lookup", { method: "POST", body: payload }),

  ocrReceipt: (file) => {
    const fd = new FormData();
    fd.append("file", file);
    return request("/ai/ocr-receipt", { method: "POST", body: fd, isForm: true });
  },

  ocrCommit: (items) => request("/ai/ocr-commit", { method: "POST", body: items }),

  getRecipes: () => request("/ai/recipes"),
  getGeminiRecipes: () => request("/ai/recipes-gemini")
};
